SELECT company_id, security_level
FROM security
WHERE security_level = 'medium';

SELECT company_name
FROM listed_companies
WHERE ipo_date = '1980-12-12';

SELECT COUNT(*) 
FROM security 
WHERE security_level = 'high';

SELECT company_name 
FROM listed_companies 
WHERE company_id NOT IN (SELECT company_id FROM investment_decisions);

SELECT COUNT(*) 
FROM listed_companies 
WHERE industry = 'Technology';

SELECT company_name, industry
FROM listed_companies
ORDER BY company_name ASC;

SELECT company_name, industry, sector
FROM listed_companies
WHERE company_id > 1;

SELECT u.user_name
FROM users u
JOIN user_tool_access uta ON u.user_id = uta.user_id
WHERE uta.access_date = (
  SELECT MAX(access_date) FROM user_tool_access
);

SELECT pattern, pattern_type, pattern_strength
FROM pattern_recognition
WHERE company_id = 1;

SELECT lc.company_name, sp.price AS closing_price
FROM listed_companies lc
JOIN stock_prices sp ON lc.company_id = sp.company_id;

SELECT user_id
FROM investment_decisions
WHERE decision = 'buy' AND company_id = 1;

SELECT user_id, COUNT(*) as total_investment_decisions
FROM investment_decisions
GROUP BY user_id;

SELECT company_name
FROM listed_companies
WHERE company_id IN (SELECT company_id FROM pattern_recognition WHERE pattern = 'head and shoulders');
